const config = $input.first().json;
const now = new Date().toISOString();
const headers = {
  'apikey': config.SUPABASE_KEY,
  'Authorization': `Bearer ${config.SUPABASE_KEY}`,
  'Content-Type': 'application/json',
};

// Obtener items pendientes cuyo next_retry_at ya pasó
const resp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_retry_queue?status=eq.pending&next_retry_at=lte.${now}&order=next_retry_at.asc&limit=3`,
  { headers: { 'apikey': config.SUPABASE_KEY, 'Authorization': `Bearer ${config.SUPABASE_KEY}` } }
);
const items = await resp.json();

if (!Array.isArray(items) || items.length === 0) {
  console.log('No hay items en cola de reintentos');
  return [];
}

console.log(`${items.length} items en cola de reintentos`);

// Marcar como processing
for (const item of items) {
  await fetch(
    `${config.SUPABASE_URL}/rest/v1/workana_retry_queue?id=eq.${item.id}`,
    {
      method: 'PATCH',
      headers,
      body: JSON.stringify({ status: 'processing', updated_at: now }),
    }
  );
}

return items.map(item => ({ json: { ...item, config } }));

const result = $input.first().json;
const retryItem = $('Obtener Pendientes').item.json;
const config = retryItem.config;
const now = new Date().toISOString();
const headers = {
  'apikey': config.SUPABASE_KEY,
  'Authorization': `Bearer ${config.SUPABASE_KEY}`,
  'Content-Type': 'application/json',
};

if (result.success) {
  // Éxito: marcar como completed
  await fetch(
    `${config.SUPABASE_URL}/rest/v1/workana_retry_queue?id=eq.${retryItem.id}`,
    { method: 'PATCH', headers, body: JSON.stringify({ status: 'completed', updated_at: now }) }
  );
  // Actualizar proyecto a 'sent'
  if (retryItem.project_id) {
    await fetch(
      `${config.SUPABASE_URL}/rest/v1/workana_projects?id=eq.${retryItem.project_id}`,
      { method: 'PATCH', headers, body: JSON.stringify({ status: 'sent', auto_sent: true }) }
    );
  }
  console.log('✅ Reintento exitoso: ' + retryItem.project_url);
} else {
  const newAttempt = (retryItem.attempt_count || 0) + 1;

  if (newAttempt >= (retryItem.max_attempts || 3)) {
    // Máximo de intentos
    await fetch(
      `${config.SUPABASE_URL}/rest/v1/workana_retry_queue?id=eq.${retryItem.id}`,
      { method: 'PATCH', headers, body: JSON.stringify({ status: 'failed', attempt_count: newAttempt, error_message: result.message || 'Max retries', updated_at: now }) }
    );
    console.log('❌ Máximo reintentos alcanzado: ' + retryItem.project_url);
  } else {
    // Backoff exponencial: 15min → 60min → 240min
    const backoffMs = Math.pow(4, newAttempt - 1) * 15 * 60 * 1000;
    const nextRetry = new Date(Date.now() + backoffMs).toISOString();

    await fetch(
      `${config.SUPABASE_URL}/rest/v1/workana_retry_queue?id=eq.${retryItem.id}`,
      { method: 'PATCH', headers, body: JSON.stringify({ status: 'pending', attempt_count: newAttempt, next_retry_at: nextRetry, error_message: result.message || 'Retry failed', updated_at: now }) }
    );
    console.log(`🔄 Reintento ${newAttempt}/3 fallido, próximo en ${Math.round(backoffMs/60000)} min`);
  }
}

return [{ json: { processed: true, success: result.success } }];
